(function(){var items=[{"id":"l_06_01","q":"투안 씨는 어는 나라 사람입니까?","audio":"안녕하세요. 저는 투안입니다. 베트남 사람입니다. 만나서 반갑습니다.","a":["한국 사람입니다","태국 사람입니다","베트남 사람입니다","파키스탄 사람입니다"],"c":"베트남 사람입니다","ex":"Dalam audio, Tuan secara jelas menyebutkan bahwa dia adalah orang Vietnam (베트남 사람).","romaji":"Tuan ssineun eoneu nara saram-imnikka?","ch":6},{"id":"l_06_02","q":"이 사람은 직업이 무엇입니까?","audio":"민수 씨는 학생입니까? 아니요, 저는 회사원입니다. 투안 씨도 회사원입니까?","a":["학생입니다","요리사입니다","의사입니다","회사원입니다"],"c":"회사원입니다","ex":"Pembicara (Minsu) menyatakan bahwa dia bukan pelajar, melainkan pegawai perusahaan (회사원).","romaji":"I sarameun jigyeobi mueosimnikka?","ch":6},{"id":"l_06_03","q":"말하는 사람은 누구입니까?","audio":"안녕하세요. 저는 이영진입니다. 인도네시아 사람입니다. 처음 뽑겠습니다.","a":["이영진 씨입니다","이민수 씨입니다","투안 씨입니다","리한 씨입니다"],"c":"이영진 씨입니다","ex":"Audio berisi pengenalan diri oleh Lee Yeong-jin.","romaji":"Malhaneun sarameun nugu-imnikka?","ch":6},{"id":"l_06_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"가: 안녕하세요. 저는 바루입니다. 나: 반갑습니다, 바루 씨. 저는 준구입니다. 바루 씨는 어는 나라 사람입니까? 가: 저는 파키스탄 사람입니다. 준구 씨는 학생입니까? 나: 아니요, 저는 공무원입니다. 바루 씨는 직업이 무엇입니까? 가: 저는 기술자입니다.","a":["바루 씨는 파키스탄 사람입니다","준구 씨는 학생입니다","바루 씨는 기술자입니다","준구 씨는 공무원입니다"],"c":"준구 씨는 학생입니다","ex":"준구 (Jungu) mengatakan \"아니요, 저는 공무원입니다\" yang berarti dia adalah PNS, bukan pelajar.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":6},{"id":"l_06_05","q":"들은 내용과 같은 직업을 고르십시오.","audio":"안녕하세요. 제 이름은 리한입니다. 저는 파키스탄에서 왔습니다. 제 직업은 목수입니다. 오늘은 처음 회사에 왔습니다. 만나서 정말 반갑습니다. 우리 같이 열심히 일합시다. 감사합니다.","a":["요리사","간호사","목수","농부"],"c":"목수","ex":"Rihan menyebutkan bahwa pekerjaannya adalah tukang kayu (목수).","romaji":"Deureun naeyong-gwa gateun jigeobeul goreusipsio.","ch":6},{"id":"l_07_01","q":"여기가 어디입니까?","audio":"여기가 사무실입니까? 네, 사무실입니다. 화장실은 어디입니까? 저기입니다.","a":["식당입니다","화장실입니다","사무실입니다","기숙사입니다"],"c":"사무실입니다","ex":"Pembicara pertama bertanya apakah itu kantor (사무실) dan dijawab \"Ya\".","romaji":"Yeogiga eodi-imnikka?","ch":7},{"id":"l_07_02","q":"이것은 무엇입니까?","audio":"투안 씨, 이게 뭐예요? 아, 이건 제 가족사진이에요. 그리고 이건 기숙사 열쇠예요.","a":["여권입니다","지갑입니다","가족사진입니다","가방입니다"],"c":"가족사진입니다","ex":"Benda yang ditanyakan diidentifikasi sebagai foto keluarga (가족사진).","romaji":"Igeoseun mueosimnikka?","ch":7},{"id":"l_07_03","q":"화장실이 어디에 있습니까?","audio":"실예합니다. 식당이 어디입니까? 식당은 저기입니다. 그럼 화장실은 어디입니까? 화장실은 식당 옆에 있습니다.","a":["식당 앞","식당 옆","사무실 앞","기숙사 옆"],"c":"식당 옆","ex":"Lokasi kamar mandi ada di sebelah restoran (식당 옆).","romaji":"Hwajangsiri eodie isseumnikka?","ch":7},{"id":"l_07_04","q":"들은 내용과 관계없는 물건을 고르십시오.","audio":"제 가방 안에 물건이 많아요. 여권하고 지갑이 있어요. 그리고 추워서 이불도 가져왔요. 아, 기숙사 열쇠도 가방에 있어요. 그런데 우산은 없어요.","a":["여권","지갑","이불","우산"],"c":"우산","ex":"Pembicara menyebutkan paspor, dompet, selimut, dan kunci ada di tas, tetapi payung (우산) tidak ada.","romaji":"Deureun naeyong-gwa gwangye-eomneun mulgeoneul goreusipsio.","ch":7},{"id":"l_07_05","q":"여자는 지금 어디에 가고 싶어합니까?","audio":"가: 여기가 시장입니까? 나: 아니요, 마트입니다. 시장은 저기 머리 있어요. 가: 그래요? 저는 오늘 과일을 사고 싶어요. 그럼 마트에서 과일을 팔아요? 나: 네, 마트에도 과일이 많아요. 가: 그럼 여기서 쇼핑할게요. 감사합니다.","a":["시장","마트","회사","미용실"],"c":"마트","ex":"Wanita tersebut memutuskan untuk belanja di mart (마트) setelah mengetahui mart juga menjual buah.","romaji":"Yeojaneun jigeum eodie gago sipeohamnikka?","ch":7},{"id":"l_08_01","q":"투안 씨는 지금 무엇을 합니까?","audio":"투안 씨, 지금 뭐 해요? 저는 지금 싸어요. 그리고 요리해요. 수루 씨는 뭐 해요?","a":["자요","싸어요","일해요","운동해요"],"c":"싸어요","ex":"Tuan menjawab bahwa dia sedang mandi/mencuci (싸어요).","romaji":"Tuan ssineun jigeum mueoseul hamnikka?","ch":8},{"id":"l_08_02","q":"지금 몇 시입니까?","audio":"지금 몇 시예요? 열한 시예요. 열두 시 삼⽍ 분에 점심을 먹어요.","a":["10:00","11:00","12:30","01:30"],"c":"11:00","ex":"Audio menyebutkan saat ini jam 11 tepat (열한 시).","romaji":"Jigeum myeot si-imnikka?","ch":8},{"id":"l_08_03","q":"남자는 언제 운동을 합니까?","audio":"리한 씨, 보통 언제 운동해요? 저는 아침에 일찍 운동해요. 그리고 저녑에는 집에서 쉬어요.","a":["아침","점심","오후","새벽"],"c":"아침","ex":"Rihan menyatakan dia berolahraga di pagi hari (아침).","romaji":"Namjaneun eonje undongeul hamnikka?","ch":8},{"id":"l_08_04","q":"여자의 일과에 대한 설명으로 맞는 것을 고르십시오.","audio":"저는 아침 읿C극 시에 일어나요. 여더극 시에 아침을 먹고 회사에 가요. 아호극 시부터 오후 여섟 시까지 일해요. 퇴근 후에 집에서 저녑을 먹고 텔레비전을 봐요. 밤 열한 시에 자요.","a":["오전 8시에 일을 시작합니다","오후 6시에 퇴근합니다","오후 7시에 일어난니다","밤 10시에 장니다"],"c":"오후 6시에 퇴근합니다","ex":"Pembicara mengatakan dia bekerja sampai jam 6 sore, yang berarti dia pulang (퇴근) jam 6 sore.","romaji":"Yeojayi ilgwa-e daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":8},{"id":"l_08_05","q":"두 사람은 몇 시에 만납니까?","audio":"가: 우리 오늘 저녑에 같이 운동할까요? 나: 좋아요. 몇 시에 만날까요? 가: 읿C극 시에 만날까요? 나: 일극 시는 너무 빨라요. 여더극 시 삼⽍ 분에 만나요. 가: 네, 알겠습니다. 그때 봐요.","a":["07:00","08:00","08:30","09:30"],"c":"08:30","ex":"Meskipun jam 7 diajukan, mereka sepakat bertemu pada 8:30 (여더극 시 삼⽍ 분).","romaji":"Du sarameun myeot sie mannamnikka?","ch":8},{"id":"l_09_01","q":"투안 씨 가족은 몇 명입니까?","audio":"투안 씨는 가족이 몇 명이에요? 어더니하고 형하고 저, 세 명이에요.","a":["두 명","세 명","네 명","다섯 명"],"c":"세 명","ex":"Tuan menyebutkan keluarganya ada 3 orang (세 명).","romaji":"Tuan ssi gajogeun myeot myeong-imnikka?","ch":9},{"id":"l_09_02","q":"여동생은 지금 무엇을 합니까?","audio":"여동생이 정말 예브요. 지금 어디에 있어요? 한국에 있어요. 학교에서 공부해요.","a":["요리해요","일해요","쇼핑해요","공부해요"],"c":"공부해요","ex":"Adik perempuannya sedang belajar (공부해요) di sekolah.","romaji":"Yeodongsaengeun jigeum mueoseul hamnikka?","ch":9},{"id":"l_09_03","q":"이 사람은 누구입니까?","audio":"이 사람이 누구예요? 우리 누나예요. 누나는 키가 커요. 그리고 정말 날씨해요.","a":["형","누나","여동생","남동생"],"c":"누나","ex":"Pembicara mengidentifikasi orang dalam foto sebagai kakak perempuannya (누나).","romaji":"I sarameun nugu-imnikka?","ch":9},{"id":"l_09_04","q":"가족에 대한 설명으로 맞는 것을 고르십시오.","audio":"우리 가족은 네 명이에요. 아버지하고 어더니는 인도네시아에 살아요. 형은 한국에서 일해요. 그리고 저는 지금 기숙사에 있어요. 저는 동생이 없어요.","a":["가족이 모두 한국에 삵니다","형은 인도네시아에 있습니다","저는 남동생이 있습니다","아버지는 인도네시아에 사십니다"],"c":"아버지는 인도네시아에 사십니다","ex":"Audio menyatakan ayah dan ibu tinggal di Indonesia (인도네시아에 살아요).","romaji":"Gajoge daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":9},{"id":"l_09_05","q":"남동생의 특징이 아닌 것을 고르십시오.","audio":"제 남동생을 소개할게요. 남동생은 스무 살이에요. 아주 뚜뚜해요. 그리고 활발해서 운동을 정말 좋아해요. 하지만 조금 얄전한 성격도 있어요. 키는 조금 작아요.","a":["뚜뚜합니다","운동을 좋아합니다","키가 아주 큩니다","스무 살입니다"],"c":"키가 아주 큩니다","ex":"Pembicara menyebutkan adiknya pendek (키는 조금 작아요), jadi \"sangat tinggi\" adalah salah.","romaji":"Namdongsaengui teukjing-i anin geoseul goreusipsio.","ch":9},{"id":"l_10_01","q":"투안 씨는 언제 한국에 왔습니까?","audio":"투안 씨는 언제 한국에 왔어요? 올해 이월 십일에 왔어요. 수루 씨는요?","a":["작년 7월","올해 2월 10일","올해 3월 10일","내년 1월"],"c":"올해 2월 10일","ex":"Tuan datang tanggal 10 Februari tahun ini (올해 2월 10일).","romaji":"Tuan ssineun eonje Hanguge wasseumnikka?","ch":10},{"id":"l_10_02","q":"어제 무엇을 했습니까?","audio":"리한 씨, 어제 뭐 했어요? 친구하고 PC방에서 게임했어요. 투안 씨는요?","a":["도서관에서 공부했어요","공원에서 산책했어요","PC방에서 게임했어요","극장에서 영화를 뵌어요"],"c":"PC방에서 게임했어요","ex":"Rihan bermain game di warnet (PC방에서 게임했어요).","romaji":"Eoje mueoseul haesseumnikka?","ch":10},{"id":"l_10_03","q":"여자는 오늘 무엇을 합니까?","audio":"오늘은 친구를 만나요. 커피숲에서 같이 커피를 마셔요. 그리고 백화점에서 쇼핑할 거예요.","a":["책을 읽어요","노래해요","커피를 마셔요","영화를 봐요"],"c":"커피를 마셔요","ex":"Wanita tersebut akan minum kopi (커피를 마셔요) di kafe.","romaji":"Yeojaneun oneul mueoseul hamnikka?","ch":10},{"id":"l_10_04","q":"남자의 지난주 일과를 순서대로 고르십시오.","audio":"지난주는 정말 바빠쎈어요. 월요일에는 도서관에서 한국어를 공부했어요. 수요일에는 친구하고 영화관에서 영화를 뵌어요. 그리고 토요일에는 백화점에서 가족 선물을 ฼어요. 일요일에는 집에서 푸국 쉼었어요.","a":["공부 - 영화 - 쇼핑 - 휴식","쇼핑 - 공부 - 영화 - 운동","영화 - 쇼핑 - 공부 - 산책","공부 - 운동 - 영화 - 쇼핑"],"c":"공부 - 영화 - 쇼핑 - 휴식","ex":"Urutan kegiatannya adalah: belajar (공부), nonton film (영화), belanja (쇼핑/฼어요), dan istirahat (휴식/쉼었어요).","romaji":"Namjayi jinanju ilgwareul sunseodaero goreusipsio.","ch":10},{"id":"l_10_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"가: 투안 씨, 어제 어디에 갔어요? 나: 공원에 갔어요. 공원에서 산책하고 운동했어요. 리한 씨는요? 가: 저는 도서관에 갔어요. 도서관에서 한국어를 공부했어요. 나: 시험이 언제예요? 가: 다음 주 금요일이에요. 그래서 열심히 공부하고 있어요.","a":["투안 씨는 어제 도서관에 갔습니다","리한 씨는 어제 운동을 했습니다","시험은 다음 주 금요일입니다","두 사람은 어제 같이 공부했습니다"],"c":"시험은 다음 주 금요일입니다","ex":"Rihan menyatakan ujiannya adalah Jumat depan (다음 주 금요일).","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":10},{"id":"l_11_01","q":"남자는 무엇을 얼마나 삽니까?","audio":"주인: 어서 오세요. 뭘 드릴까요? 손님: 사과 다섯 개 주세요. 그리고 물 두 병 주세요.","a":["사과 세 개, 물 한 병","사과 다섯 개, 물 두 병","사과 다섯 개, 물 세 병","사과 두 개, 물 다섯 병"],"c":"사과 다섯 개, 물 두 병","ex":"Pembicara meminta 5 buah apel dan 2 botol air.","romaji":"Namjaneun mueoseul eolmana samnikka?","ch":11},{"id":"l_11_02","q":"오렌지는 모두 얼마입니까?","audio":"가: 오렌지 얼마예요? 나: 한 개에 천 원이에요. 가: 그럼 오렌지 다섯 개 주세요.","a":["천 원","삼천 원","오천 원","만 원"],"c":"오천 원","ex":"Harga satu jeruk 1.000 won, beli 5 = 5.000 won.","romaji":"Orenjineun modu eolmaimnikka?","ch":11},{"id":"l_11_03","q":"여자는 무엇을 부탁합니까?","audio":"가: 봉투에 넣어 드릴까요? 나: 네, 봉투에 좀 넣어 주세요. 그리고 이 빵 좀 포장해 주세요.","a":["환불해 주세요","바꿔 주세요","깎아 주세요","넣어 주세요"],"c":"넣어 주세요","ex":"Wanita meminta barang dimasukkan ke kantong.","romaji":"Yeojaneun mueoseul butakhamnikka?","ch":11},{"id":"l_11_04","q":"대화 내용과 같은 것을 고르십시오.","audio":"손님: 사장님, 이 운동화 얼마예요? 주인: 오만 오천 원이에요. 손님: 오만 오천 원요? 좀 비싸요. 깎아 주세요. 주인: 그래요? 알았어요. 오만 원만 주세요. 손님: 고맙습니다. 여기 지폐로 오만 원 있어요.","a":["운동화는 오만 원입니다","손님은 값을 깎았습니다","주인은 깎아 주지 않았습니다","손님은 신용카드로 계산했습니다"],"c":"손님은 값을 깎았습니다","ex":"Pembeli minta diskon, dari 55.000 jadi 50.000 won.","romaji":"Daehwa naeyonggwa gateun geoseul goreusipsio.","ch":11},{"id":"l_11_05","q":"들은 내용으로 알맞지 않은 것을 고르십시오.","audio":"가: 어서 오세요. 뭘 드릴까요? 나: 수박 있어요? 가: 네, 있어요. 수박 한 통에 이만 원이에요. 나: 수박이 너무 비싸네요. 포도는 얼마예요? 가: 포도는 한 송이에 오천 원이에요. 나: 그럼 포도 두 송이 주세요. 여기 만 원 있습니다.","a":["수박 한 통에 이만 원입니다","포도는 한 송이에 오천 원입니다","남자는 수박 한 통을 샀습니다","남자는 모두 만 원을 냈습니다"],"c":"남자는 수박 한 통을 샀습니다","ex":"Pria tidak jadi beli semangka, beli 2 anggur 10.000 won.","romaji":"Deureun naeyong-euro almaji anneun geoseul goreusipsio.","ch":11},{"id":"l_12_01","q":"은행은 어디에 있습니까?","audio":"투안: 이 건물에 은행이 있어요? 여자: 네, 있어요. 지하 1층에 있어요. 지하로 내려가세요.","a":["1층","2층","지하 1층","건물 밖"],"c":"지하 1층","ex":"Bank di lantai 1 bawah tanah.","romaji":"Eunhengeun eodie isseumnikka?","ch":12},{"id":"l_12_02","q":"약국은 어디에 있습니까?","audio":"수루: 이 근처에 약국이 있어요? 남자: 네, 저기 병원이 보여요? 약국은 병원 옆에 있어요.","a":["병원 위","병원 옆","병원 뒤","병원 안"],"c":"병원 옆","ex":"Apotek di samping rumah sakit.","romaji":"Yakgugeun eodie isseumnikka?","ch":12},{"id":"l_12_03","q":"남자는 어디로 가야 합니까?","audio":"가: 우체국이 어디에 있어요? 나: 저 사거리에서 오른쪽으로 가세요. 그러면 우체국이 있어요.","a":["왼쪽","오른쪽","앞으로","뒤로"],"c":"오른쪽","ex":"Belok kanan di perempatan.","romaji":"Namjaneun eodiro gaya hamnikka?","ch":12},{"id":"l_12_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"가: 실례합니다. 이 건물에 편의점이 있어요? 나: 네, 3층에 있어요. 가: 어떻게 가요? 나: 저기 계단으로 올라가세요. 그러면 식당 옆에 편의점이 있어요. 가: 아, 네. 감사합니다.","a":["편의점은 2층에 있습니다","편의점은 식당 옆에 있습니다","편의점은 건물 밖에 있습니다","계단으로 내려가야 합니다"],"c":"편의점은 식당 옆에 있습니다","ex":"Minimarket lantai 3 sebelah restoran.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":12},{"id":"l_12_05","q":"남자는 지금 어디에 있습니까?","audio":"여: 투안 씨, 어디예요? 남: 저는 지금 기숙사 1층에 있어요. 세탁실에서 빨래를 하고 있어요. 여: 그래요? 저는 2층 휴게실에 있어요. 1층으로 내려오세요. 같이 식당에 가요. 남: 네, 알겠어요. 지금 갈게요.","a":["1층 세탁실","2층 휴게실","지하 주차장","건물 밖"],"c":"1층 세탁실","ex":"Tuan di ruang laundry lantai 1.","romaji":"Namjaneun jigeum eodie isseumnikka?","ch":12},{"id":"l_13_01","q":"두 사람은 내일 무엇을 합니까?","audio":"투안: 수루 씨, 내일 시간 있어요? 우리 같이 영화 볼까요? 수루: 좋아요. 같이 영화 봐요.","a":["쇼핑해요","운동해요","영화를 봐요","한국어를 공부해요"],"c":"영화를 봐요","ex":"Mereka janji nonton film.","romaji":"Du sarameun naeil mueoseul hamnikka?","ch":13},{"id":"l_13_02","q":"두 사람은 어디에서 만납니까?","audio":"가: 우리 내일 어디에서 만날까요? 나: 백화점 앞에서 볼까요? 가: 좋아요. 거기에서 만나요.","a":["시청 앞","회사 앞","극장 앞","백화점 앞"],"c":"백화점 앞","ex":"Sepakat di depan department store.","romaji":"Du sarameun eodie-seo mannamnikka?","ch":13},{"id":"l_13_03","q":"여자는 무엇을 하고 싶어합니까?","audio":"가: 오늘 뭐 하고 싶어요? 나: 날씨가 좋으니까 공원에서 같이 산책하고 싶어요.","a":["노래하고 싶어요","쇼핑하고 싶어요","산책하고 싶어요","게임하고 싶어요"],"c":"산책하고 싶어요","ex":"Ingin jalan-jalan karena cuaca bagus.","romaji":"Yeojaneun mueoseul hago sipeohamnikka?","ch":13},{"id":"l_13_04","q":"두 사람의 약속에 대한 설명으로 맞는 것을 고르십시오.","audio":"남: 수루 씨, 오늘 저녁에 같이 밥 먹을까요? 여: 미안해요. 오늘은 좀 바빠요. 내일은 어때요? 남: 내일도 괜찮아요. 그럼 내일 저녁 일곱 시에 만날까요? 여: 일곱 시는 좀 빨라요. 여덟 시에 시청 앞에서 봐요. 남: 네, 좋아요. 내일 봐요.","a":["오늘 저녁에 만납니다","내일 일곱 시에 만납니다","내일 여덟 시에 만납니다","회사 앞에서 만납니다"],"c":"내일 여덟 시에 만납니다","ex":"Batal hari ini, sepakat besok jam 8 di depan balai kota.","romaji":"Du saramui yaksoge daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":13},{"id":"l_13_05","q":"여자는 내일 무엇을 할 것입니까?","audio":"남: 수루 씨, 내일 뭐 할 거예요? 친구하고 영화 볼 거예요? 여: 아니요, 영화는 어제 봤어요. 내일은 은행에 가고 싶어요. 남: 은행에는 왜요? 여: 고향에 돈을 보내야 해서 환전을 하려고 해요. 그 후에 친구를 만나서 쇼핑할 거예요.","a":["영화를 봅니다","환전을 합니다","요리를 합니다","한국어를 공부합니다"],"c":"환전을 합니다","ex":"Ke bank untuk menukar uang.","romaji":"Yeojaneun naeil mueoseul hal geosimnikka?","ch":13},{"id":"l_14_01","q":"식당에 몇 명이 왔습니까?","audio":"종업원: 어서 오세요. 몇 분이세요? 투안: 두 명이요. 자리 있어요? 종업원: 네, 있어요. 이쪽으로 앉으세요.","a":["한 명","두 명","세 명","네 명"],"c":"두 명","ex":"Tamu menjawab 'dua orang'.","romaji":"Sikdange myeot myeongi wasseumnikka?","ch":14},{"id":"l_14_02","q":"리한 씨는 무엇을 주문했습니까?","audio":"종업원: 뭐 드릴까요? 리한: 저는 비빔밥 먹을래요. 투안 씨는 뭐 먹을래요? 투안: 저는 김치찌개 먹을래요.","a":["김치찌개","된장찌개","비빔밥","갈비탕"],"c":"비빔밥","ex":"Rihan spesifik pesan bibimbap.","romaji":"Rihan ssineun mueoseul jumun-haesseumnikka?","ch":14},{"id":"l_14_03","q":"김치찌개 맛이 어때요?","audio":"가: 김치찌개가 안 매워요? 나: 조금 매워요. 하지만 정말 맛있어요. 가: 그래요? 그럼 저도 다음에 먹어 볼게요.","a":["달아요","짜요","매워요","시어요"],"c":"매워요","ex":"Agak pedas tapi enak.","romaji":"Gimchijjigae masi eottaeyo?","ch":14},{"id":"l_14_04","q":"두 사람이 주문한 음식은 모두 무엇입니까?","audio":"종업원: 어서 오세요. 뭐 드릴까요? 손님 1: 여기 메뉴판 좀 주세요. 음... 저는 갈비탕 먹을래요. 수미 씨는요? 손님 2: 저는 어제 갈비탕을 먹었어요. 그래서 오늘은 비빔밥을 먹을래요. 손님 1: 사장님, 여기 갈비탕 하나하고 비빔밥 하나 주세요.","a":["갈비탕 두 그릇","비빔밥 두 그릇","갈비탕 한 그릇, 비빔밥 한 그릇","김치찌개 한 그릇, 갈비탕 한 그릇"],"c":"갈비탕 한 그릇, 비빔밥 한 그릇","ex":"Galbitang + bibimbap.","romaji":"Du sarami jumun-han eumsigeun modu mueosimnikka?","ch":14},{"id":"l_14_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"리한: 투안 씨는 김치찌개를 좋아해요? 투안: 네, 정말 좋아해요. 리한 씨는요? 리한: 아니요, 저는 안 좋아해요. 저는 매운 음식을 안 좋아해요. 하지만 불고기는 정말 좋아해요. 불고기는 아주 달고 맛있어요.","a":["투안 씨는 김치찌개를 좋아합니다.","리한 씨는 매운 음식을 좋아하지 않습니다.","투안 씨는 불고기를 주문했습니다.","불고기는 맛이 답니다."],"c":"투안 씨는 불고기를 주문했습니다.","ex":"Rihan yang suka bulgogi, bukan Tuan.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":14},{"id":"l_15_01","q":"오늘 날씨는 어떻습니까?","audio":"투안: 오늘 날씨가 참 좋네요. 수루: 네, 요즘은 날씨가 따뜻해서 기분이 정말 좋아요.","a":["추워요","흐려요","더워요","따뜻해요"],"c":"따뜻해요","ex":"Cuaca disebut hangat.","romaji":"Oneul nalssineun eotteoseumnikka?","ch":15},{"id":"l_15_02","q":"남자는 왜 기분이 좋습니까?","audio":"가: 투안 씨, 기분이 어때요? 나: 정말 좋아요. 눈이 와서 기분이 아주 좋아요.","a":["비가 와서","눈이 와서","날씨가 더워서","시험을 잘 쳐서"],"c":"눈이 와서","ex":"Senang karena turun salju.","romaji":"Namjaneun wae gibuni jouseumnikka?","ch":15},{"id":"l_15_03","q":"지금은 무슨 계절입니까?","audio":"가: 지금 날씨가 어때요? 나: 너무 더워요. 비도 많이 와요.","a":["봄","여름","가을","겨울"],"c":"여름","ex":"Panas + banyak hujan = musim panas.","romaji":"Jigeumeun museun gyejeol-imnikka?","ch":15},{"id":"l_15_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"가: 수미 씨는 무슨 계절을 좋아해요? 나: 저는 여름을 좋아해요. 투안 씨는요? 가: 저는 봄을 좋아해요. 날씨가 따뜻해서 좋아요. 나: 그렇군요. 그런데 오늘 날씨는 너무 흐리네요. 가: 네, 비가 올 것 같아요. 비가 오면 기분이 좀 우울해요.","a":["남자는 봄을 좋아합니다","여자는 여름을 좋아합니다","오늘 날씨는 아주 맑습니다","남자는 비가 오면 기분이 안 좋습니다"],"c":"오늘 날씨는 아주 맑습니다","ex":"Hari ini mendung, bukan cerah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":15},{"id":"l_15_05","q":"남자는 오늘 왜 피곤합니까?","audio":"여: 투안 씨, 얼굴이 안 좋네요. 무슨 일 있어요? 남: 아니요, 어제 일을 많이 해서 좀 피곤해요. 여: 그래요? 그럼 오늘은 일찍 집에 가서 쉬세요. 남: 네, 그러고 싶어요. 어제 잠도 못 자서 지금 너무 졸려요.","a":["비가 와서","일을 많이 해서","운동을 많이 해서","날씨가 너무 더워서"],"c":"일을 많이 해서","ex":"Lelah karena banyak kerja dan kurang tidur.","romaji":"Namjaneun oneul wae pigonhamnikka?","ch":15},{"id":"l_16_01","q":"투안 씨는 시간이 있을 때 보통 무엇을 합니까?","audio":"수루 씨, 저는 낚시를 정말 좋아해요. 그래서 시간이 있을 때 낚시하러 자주 가요. 수루 씨는 취미가 뭐예요?","a":["등산을 합니다","독서를 합니다","낚시를 합니다","여행을 합니다"],"c":"낚시를 합니다","ex":"Tuan menyatakan bahwa hobinya adalah memancing dan sering pergi memancing saat ada waktu luang.","romaji":"Tuan ssineun sigani isseul ttae botong mueoseul hamnikka?","ch":16},{"id":"l_16_02","q":"여자는 기분이 좋을 때 무엇을 합니까?","audio":"저는 기분이 좋을 때 노래를 불러요. 노래를 부르면 마음이 정말 즐거워져요. 리한 씨는 어때요?","a":["춤을 춥니다","노래를 부릅니다","잠을 잡니다","음악을 듣습니다"],"c":"노래를 부릅니다","ex":"Wanita tersebut menjelaskan bahwa ia bernyanyi (노래를 불러요) ketika merasa senang.","romaji":"Yeojaneun gibuni joeul ttae mueoseul hamnikka?","ch":16},{"id":"l_16_03","q":"두 사람은 이번 주말에 무엇을 하겠습니까?","audio":"가: 이번 주말에 시간이 있어요? 같이 테니스 치러 갈래요? 나: 좋아요. 같이 가요. 저도 테니스를 배우고 싶었어요.","a":["축구를 합니다","테니스를 칩니다","등산을 합니다","자전거를 탑니다"],"c":"테니스를 칩니다","ex":"Mereka sepakat untuk pergi bermain tenis bersama (테니스 치러 갈래요) pada akhir pekan.","romaji":"Du sarameun ibon jumare mueoseul hagetseumnikka?","ch":16},{"id":"l_16_04","q":"외국인력지원센터의 프로그램에 대한 설명으로 맞는 것은 무엇입니까?","audio":"안녕하세요. 우리 센터에서는 외국인들을 위한 다양한 교육 프로그램을 운영하고 있습니다. 한국어 수업은 매주 토요일에 있고, 컴퓨터 수업은 일요일 오후에 있습니다. 그리고 태권도를 배우고 싶은 분들은 평일 저녁에 오시면 됩니다. 모든 수업은 무료입니다.","a":["한국어 수업은 일요일에 있습니다.","컴퓨터 수업은 토요일에 있습니다.","태권도 수업은 평일 저녁에 있습니다.","모든 수업은 돈을 내야 합니다."],"c":"태권도 수업은 평일 저녁에 있습니다.","ex":"Pengumuman menyatakan kelas Taekwondo diadakan pada malam hari di hari kerja (평일 저녁).","romaji":"Oegugin-illyeok-jiwon-senteoyi peurogeuraeme daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":16},{"id":"l_16_05","q":"남자의 취미 활동에 대한 내용으로 알맞은 것을 고르십시오.","audio":"제 취미는 사진 찍기입니다. 주말마다 친구들하고 같이 아름다운 경치를 찍으러 여행을 가요. 지난주에는 제주도에 가서 바다 사진을 많이 찍었어요. 사진을 찍을 때 기분이 정말 행복해요. 나중에 사진가가 되고 싶어요.","a":["혼자서 여행하는 것을 좋아합니다.","지난주에 산에 가서 사진을 찍었습니다.","사진 찍는 것이 남자의 취미입니다.","주말에는 집에서 음악을 듣습니다."],"c":"사진 찍는 것이 남자의 취미입니다.","ex":"Pria tersebut menjelaskan bahwa hobinya adalah mengambil foto (사진 찍기) dan ia merasa bahagia saat melakukannya.","romaji":"Namjayi chwimi hwaldonge daehan naeyong-euro almajeun geoseul goreusipsio.","ch":16},{"id":"l_17_01","q":"리한 씨는 제주도에 가 봤습니까?","audio":"투안: 리한 씨는 제주도에 가 봤어요? 리한: 네, 가 봤어요. 제주도는 바다가 너무 아름다웠어요.","a":["아니요, 안 가 봤어요.","네, 가 봤어요.","내년에 갈 거예요.","어제 갔어요."],"c":"네, 가 봤어요.","ex":"Rihan menjawab \"Ya, sudah pernah\" (네, 가 봤어요) ketika ditanya tentang kunjungannya ke Pulau Jeju.","romaji":"Rihan ssineun Jejudo-e ga bwasseumnikka?","ch":17},{"id":"l_17_02","q":"남자는 이번 휴가 때 무엇을 할 것입니까?","audio":"이번 여름 휴가 때 친구들하고 설악산에 갈 거예요. 거기에서 등산도 하고 사진도 많이 찍을 거예요. 벌써 기차 표도 샀어요.","a":["바다에 갑니다","설악산에 갑니다","제주도에 갑니다","집에 있습니다"],"c":"설악산에 갑니다","ex":"Pria tersebut berencana pergi ke Gunung Seorak (설악산) pada liburan kali ini.","romaji":"Namjaneun ibon hyuga ttae mueoseul hal geosimnikka?","ch":17},{"id":"l_17_03","q":"남자는 여행을 위해 무엇을 준비했습니까?","audio":"가: 투안 씨, 여행 준비 다 했어요? 나: 네, 비행기 표도 사고 숙소도 벌써 다 예약했어요. 짐만 싸면 돼요.","a":["기념품","등산복","표와 숙소 예약","사진기"],"c":"표와 숙소 예약","ex":"Tuan sudah membeli tiket pesawat dan memesan penginapan (숙소 예약).","romaji":"Namjaneun yeohaengeul wihae mueoseul junbi-haesseumnikka?","ch":17},{"id":"l_17_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 리한 씨, 부산 여행은 어땠어요? 남: 정말 재미있었어요. 바다가 아주 아름다웠고 맛있는 음식도 많았어요. 여: 부산에서 사진도 많이 찍었어요? 남: 네, 많이 찍었어요. 그런데 사람이 너무 많아서 조금 복잡했어요. 다음에는 평일에 가고 싶어요.","a":["부산은 바다가 아름답습니다.","부산에는 맛있는 음식이 많습니다.","남자는 사진을 한 장도 안 찍었습니다.","부산에는 사람이 많아서 복잡했습니다."],"c":"남자는 사진을 한 장도 안 찍었습니다.","ex":"Pria tersebut mengatakan ia mengambil banyak foto (많이 찍었어요), sehingga opsi C salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":17},{"id":"l_17_05","q":"들은 내용과 일치하는 것을 고르십시오.","audio":"한국에는 아름다운 관광지가 참 많습니다. 서울에는 경복궁과 한강 유람선이 유명하고, 강원도는 산과 바다가 모두 있어서 사람들이 많이 찾습니다. 제주도는 한국에서 가장 큰 섬인데 경치가 아주 아름다워서 외국인 관광객들에게 인기가 많습니다.","a":["서울에는 경복궁이 없습니다.","제주도는 한국에서 가장 작은 섬입니다.","강원도는 산만 있고 바다는 없습니다.","제주도는 경치가 좋아서 인기가 많습니다."],"c":"제주도는 경치가 좋아서 인기가 많습니다.","ex":"Teks menyatakan Jeju sangat populer karena pemandangannya yang indah (경치가 아주 아름다워).","romaji":"Deureun naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":17},{"id":"l_18_01","q":"남자는 회사에 어떻게 갑니까?","audio":"가: 집에서 회사까지 어떻게 가요? 나: 보통 버스나 지하철을 타고 가요. 오늘은 지하철을 타고 왔어요.","a":["택시를 탑니다","지하철을 탑니다","자전거를 탑니다","걸어갑니다"],"c":"지하철을 탑니다","ex":"Pria tersebut hari ini datang naik kereta bawah tanah (지하철을 타고 왔어요).","romaji":"Namjaneun hoesa-e eotteoke gamnikka?","ch":18},{"id":"l_18_02","q":"집에서 시청까지 얼마나 걸립니까?","audio":"가: 여기에서 시청까지 얼마나 걸려요? 나: 버스로 30분 정도 걸려요. 하지만 지금은 차가 막혀서 좀 더 걸릴 거예요.","a":["15분","30분","1시간","2시간"],"c":"30분","ex":"Waktu tempuh normal dengan bus adalah 30 menit (30분 정도).","romaji":"Jibeoseo sicheong-kkaji eolmana geollimnikka?","ch":18},{"id":"l_18_03","q":"남자는 어디에서 내려야 합니까?","audio":"가: 실례합니다. 서울역에 가려면 어디에서 내려요? 나: 이번 정류장에서 내리세요. 그리고 건너편에서 1번 버스로 갈아타세요.","a":["기차역","이번 정류장","지하철역","공항"],"c":"이번 정류장","ex":"Instruksinya adalah turun di halte ini (이번 정류장).","romaji":"Namjaneun eodie-seo naeryeoya hamnikka?","ch":18},{"id":"l_18_04","q":"대화 내용과 같은 것을 고르십시오.","audio":"남: 회사에 올 때 차를 가지고 와요? 여: 아니요, 출퇴근 시간에는 길에 차가 너무 많아서 버스가 너무 느려요. 남: 그래요? 저는 집이 가까워서 걸어서 와요. 여: 와, 정말 좋겠네요. 저는 지하철역까지 좀 멀어서 버스를 타고 지하철로 갈아타야 해요.","a":["남자는 회사에 차를 타고 옵니다.","여자는 회사에 걸어서 옵니다.","남자의 집은 회사에서 가깝습니다.","여자는 갈아타지 않고 지하철만 탑니다."],"c":"남자의 집은 회사에서 가깝습니다.","ex":"Pria tersebut mengatakan rumahnya dekat (집이 가까워서) sehingga ia jalan kaki.","romaji":"Daehwa naeyong-gwa gateun geoseul goreusipsio.","ch":18},{"id":"l_18_05","q":"남자가 공장에 어떻게 가는지 고르십시오.","audio":"가: 오늘 공장에 가야 하는데 본사에서 공장까지 어떻게 가요? 나: 버스 정류장에서 300번 버스를 타세요. 그리고 세 번째 정류장에서 내리세요. 거기에서 공장까지는 가까우니까 조금만 걸어가면 돼요. 택시를 타면 돈이 많이 나오니까 버스를 이용하세요.","a":["택시를 타고 갑니다.","버스를 타고 내려서 걷습니다.","본사에서 계속 걸어갑니다.","지하철을 타고 갑니다."],"c":"버스를 타고 내려서 걷습니다.","ex":"Instruksinya adalah naik bus, turun di halte ketiga, lalu jalan kaki sedikit (조금만 걸어가면 돼요).","romaji":"Namjaga gongjang-e eotteoke ganeunji goreusipsio.","ch":18},{"id":"l_19_01","q":"남자는 어디에 전화를 걸었습니까?","audio":"남: 여보세요. 거기 한국가구지요? 여: 네, 맞습니다. 무엇을 도와드릴까요?","a":["도서관","한국가구","병원","우체국"],"c":"한국가구","ex":"Pria tersebut mengonfirmasi apakah itu \"Hanguk Gagu\" (Korea Furniture) dan wanita tersebut mengiyakan.","romaji":"Namjaneun eodie jeonwhareul georeotseumnikka?","ch":19},{"id":"l_19_02","q":"여자는 왜 인터넷 쇼핑을 좋아합니까?","audio":"저는 주로 인터넷에서 옷을 많이 사요. 인터넷 쇼핑은 가격도 싸고 쇼핑도 편리해서 정말 좋아요. 수루 씨도 한번 해 보세요.","a":["옷이 예뻐서","사람이 많아서","싸고 편리해서","직접 볼 수 있어서"],"c":"싸고 편리해서","ex":"Wanita tersebut menyukai belanja online karena murah dan praktis (싸고 편리해서).","romaji":"Yeojaneun wae inteonet syoping-eul joahamnikka?","ch":19},{"id":"l_19_03","q":"남자는 지금 무엇을 하고 있습니까?","audio":"가: 투안 씨, 지금 뭐 해요? 나: 고향 친구하고 영상 통화를 하고 있어요. 오랜만에 친구 얼굴을 보니까 정말 기뻐요.","a":["문자를 보냅니다","인터넷을 합니다","영상 통화를 합니다","사진을 찍습니다"],"c":"영상 통화를 합니다","ex":"Tuan sedang melakukan panggilan video (영상 통화) dengan temannya.","romaji":"Namjaneun jigeum mueoseul hago isseumnikka?","ch":19},{"id":"l_19_04","q":"대화 내용으로 알 수 있는 것은 무엇입니까?","audio":"여: 리한 씨, 한국어 공부를 더 하고 싶은데 어디가 좋아요? 남: 외국인력지원센터에 전화해 보세요. 거기에서 무료로 가르쳐 줘요. 여: 그래요? 전화번호를 알아요? 남: 저는 잘 몰라요. 114에 전화해서 물어보세요. 아주 친절하게 안내해 줄 거예요.","a":["남자는 한국어 선생님입니다.","여자는 지금 한국어를 가르칩니다.","114에서 전화번호를 물어볼 수 있습니다.","외국인력지원센터는 수업료가 비쌉니다."],"c":"114에서 전화번호를 물어볼 수 있습니다.","ex":"Rihan menyarankan untuk menelepon 114 untuk menanyakan nomor telepon pusat bantuan.","romaji":"Daehwa naeyong-euro al su itneun geoseun mueosimnikka?","ch":19},{"id":"l_19_05","q":"인터넷 가입에 대한 설명으로 맞는 것을 고르십시오.","audio":"한국 사이트에 회원 가입을 하려면 몇 가지 정보가 필요합니다. 먼저 아이디와 비밀번호를 정해야 합니다. 그리고 외국인의 경우에는 외국인등록번호가 꼭 있어야 가입할 수 있는 사이트가 많습니다. 가입이 끝나면 로그인해서 서비스를 이용하면 됩니다.","a":["아이디는 필요 없습니다.","외국인은 가입할 수 없습니다.","가입할 때 외국인등록번호가 필요할 수 있습니다.","로그인을 먼저 해야 가입이 됩니다."],"c":"가입할 때 외국인등록번호가 필요할 수 있습니다.","ex":"Disebutkan bahwa bagi orang asing, seringkali diperlukan nomor registrasi asing (외국인등록번호) untuk mendaftar.","romaji":"Inteonet gaibe daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":19},{"id":"l_20_01","q":"남자는 무엇을 하겠습니까?","audio":"여: 방이 너무 더럽네요. 같이 청소할까요? 남: 좋아요. 제가 방을 쓸게요. 투안 씨는 먼지를 닦아 주세요.","a":["설거지를 합니다","방을 씁니다","먼지를 닦습니다","쓰레기를 버립니다"],"c":"방을 씁니다","ex":"Pria tersebut menawarkan diri untuk menyapu kamar (제가 방을 쓸게요).","romaji":"Namjaneun mueoseul hagetseumnikka?","ch":20},{"id":"l_20_02","q":"여자는 왜 요리하는 것을 싫어합니까?","audio":"저는 요리하는 것을 별로 안 좋아해요. 요리하는 것은 너무 어렵고 복잡해요. 그래서 보통 밖에서 밥을 사 먹어요.","a":["시간이 없어서","돈이 많이 들어서","어렵고 복잡해서","설거지가 힘들어서"],"c":"어렵고 복잡해서","ex":"Wanita tersebut menganggap memasak itu sulit dan rumit (어렵고 복잡해요).","romaji":"Yeojaneun wae yorihaneun geoseul sileohamnikka?","ch":20},{"id":"l_20_03","q":"지금 방 상태가 어떠합니까?","audio":"가: 리한 씨, 방이 왜 이렇게 지저분해요? 나: 어제 청소를 안 해서 그래요. 지금 바로 정리할게요.","a":["깨끗합니다","넓습니다","지저분합니다","조용합니다"],"c":"지저분합니다","ex":"Kamar dikatakan berantakan atau kotor (지저분해요) karena belum dibersihkan.","romaji":"Jigeum bang sangtaega eotteohamnikka?","ch":20},{"id":"l_20_04","q":"두 사람의 대화 내용과 같은 것을 고르십시오.","audio":"남: 수미 씨, 오늘 저녁에 제가 친구들을 초대했어요. 그래서 음식 준비를 좀 해야 해요. 여: 그래요? 그럼 제가 도와줄게요. 저는 장을 보러 갈게요. 남: 고마워요. 그럼 저는 그동안 집안 청소를 하고 음식을 만들게요. 여: 네, 알겠어요. 조금 이따가 마트에서 봐요.","a":["여자가 음식을 직접 만듭니다.","남자가 마트에 가서 장을 봅니다.","두 사람은 오늘 저녁에 같이 청소를 합니다.","여자가 마트에서 장을 보기로 했습니다."],"c":"여자가 마트에서 장을 보기로 했습니다.","ex":"Wanita tersebut (Sumi) menawarkan diri untuk pergi belanja keperluan (장을 보러 갈게요) ke mart.","romaji":"Du saramui daehwa naeyong-gwa gateun geoseul goreusipsio.","ch":20},{"id":"l_20_05","q":"리한 씨가 투안 씨에게 부탁한 것은 무엇입니까?","audio":"투안 씨, 저 리한이에요. 제가 오늘 아침에 옥상에 제 바지를 널었어요. 그런데 갑자기 비가 올 것 같아요. 저는 지금 밖이라서 기숙사에 못 들어가요. 투안 씨가 제 바지를 좀 걷어 주세요. 부탁해요. 고마워요.","a":["바지를 세탁해 주는 것","바지를 사다 주는 것","옥상에서 바지를 걷어 주는 것","방을 청소해 주는 것"],"c":"옥상에서 바지를 걷어 주는 것","ex":"Rihan meminta Tuan untuk mengangkat jemuran celananya (바지를 좀 걷어 주세요) karena akan turun hujan.","romaji":"Rihan ssiga Tuan ssiege butakhan geoseun mueosimnikka?","ch":20},{"id":"l_21_01","q":"남자는 왜 여기에 왔습니까?","audio":"남: 안녕하세요. 저는 아딧입니다. 사장님하고 2시에 약속이 있어서 왔습니다.","a":["선물을 사러 왔습니다","사장님을 만나러 왔습니다","집을 찾으러 왔습니다","음식을 장만하러 왔습니다"],"c":"사장님을 만나러 왔습니다","ex":"Pria tersebut (Adit) datang karena memiliki janji dengan direktur pada pukul 2 siang.","romaji":"Namjaneun wae yeogie wasseumnikka? / Annyeonghaseyo. Jeoneun Adit-imnida. Sajangnimhago dusi-e yaksogi isseoseo wasseumnida.","ch":21},{"id":"l_21_02","q":"여자는 무엇을 준비했습니까?","audio":"여: 어서 오세요. 초대에 응해 주셔서 감사합니다. 제가 갈비하고 잡채를 많이 장만했습니다. 어서 드세요.","a":["세제와 휴지","수저와 식기","갈비와 잡채","화분과 시계"],"c":"갈비와 잡채","ex":"Wanita tersebut mengatakan telah menyiapkan (장만하다) galbi dan japchae untuk tamunya.","romaji":"Yeojaneun mueoseul junbi-haesseumnikka? / Eoseo oseyo. Chodae-e eung-hae jusyeoseo gamsahamnida. Jega galbihago japchaereul mani jangman-haesseumnida. Eoseo deuseyo.","ch":21},{"id":"l_21_03","q":"두 사람은 지금 무엇을 하고 있습니까?","audio":"가: 수미 씨, 제가 상 차리는 것을 좀 도와줄까요? 나: 네, 고마워요. 그럼 이 수저를 상 위에 놓아 주세요.","a":["음식을 만듭니다","상을 차립니다","상을 치웁니다","이야기를 나눕니다"],"c":"상을 차립니다","ex":"Mereka sedang menata meja makan (상 차리다) dengan meletakkan alat makan di atas meja.","romaji":"Du sarameun jigeum mueoseul hago isseumnikka?","ch":21},{"id":"l_21_04","q":"들은 내용과 일치하는 것을 고르십시오.","audio":"가: 모니카 씨, 내일 우리 집에 올 수 있어요? 제가 이번에 이사를 해서 집들이를 하거든요. 나: 정말요? 축하해요. 선물은 뭐가 좋을까요? 가: 선물은 괜찮아요. 그냥 오세요. 나: 아니에요. 한국에서는 집들이 선물로 세제나 휴지를 많이 사 가는데 저도 세제를 준비할게요.","a":["남자는 내일 친구 집에 갑니다.","여자는 이번에 이사를 했습니다.","남자는 집들이 선물로 화분을 삽니다.","여자는 내일 집들이를 합니다."],"c":"여자는 내일 집들이를 합니다.","ex":"Monika (wanita) mengadakan acara syukuran pindah rumah (집들이) dan mengundang temannya.","romaji":"Deureun naeyonggwa ilchihaneun geoseul goreusipsio.","ch":21},{"id":"l_21_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"남: 아딧 씨, 사장님께 연락 드렸어요? 아까 잠깐 밖에 나가셨거든요. 여: 네, 아까 통화했어요. 2시에 사무실에서 뵙기로 했어요. 남: 그렇군요. 그럼 제가 커피 한 잔 드릴까요? 날씨가 많이 추운데 따뜻한 커피를 마시면서 기다리세요. 여: 네, 감사합니다. 사장님을 기다리는 동안 여기에 있을게요.","a":["여자는 사장님과 약속이 있습니다.","사장님은 지금 사무실에 계십니다.","남자는 여자에게 커피를 주려고 합니다.","지금 밖의 날씨는 춥습니다."],"c":"사장님은 지금 사무실에 계십니다.","ex":"Dalam audio disebutkan direktur sedang keluar sebentar (잠깐 밖에 나가셨어요), jadi pernyataan bahwa direktur ada di kantor adalah salah.","romaji":"Daehwa naeyonggwa dareun geoseul goreusipsio.","ch":21},{"id":"l_22_01","q":"남자는 여자에게 무엇을 하면 안 된다고 말합니까?","audio":"여: 차가 안 와요. 빨리 건너가요. 남: 여기에서 길을 건너면 안 돼요. 저기 횡단보도로 가세요.","a":["차를 타면 안 됩니다","뛰어가면 안 됩니다","무단 횡단을 하면 안 됩니다","사진을 찍으면 안 됩니다"],"c":"무단 횡단을 하면 안 됩니다","ex":"Pria melarang menyeberang sembarangan (길을 건너면 안 돼요) dan menyarankan menggunakan zebra cross.","romaji":"Namjaneun yeojage mueoseul hamyeon an doendago malhamnikka?","ch":22},{"id":"l_22_02","q":"이곳에서 할 수 없는 행동은 무엇입니까?","audio":"이곳은 주차 금지 구역입니다. 여기에 차를 세우면 안 됩니다. 주차장을 이용해 주세요.","a":["금연","음식물 반입","주차","휴대전화 사용"],"c":"주차","ex":"Audio menyatakan daerah tersebut dilarang parkir (주차 금지).","romaji":"Igoseoseo hal su eomneun haengdongeun mueosimnikka?","ch":22},{"id":"l_22_03","q":"남자가 지하철을 타려는 이유는 무엇입니까?","audio":"가: 지금 차가 많이 막히네요. 나: 네, 지금은 퇴근 시간이라서 그래요. 차가 막히니까 지하철을 타고 갑시다.","a":["지하철이 빨라서","길이 막히니까","돈이 없어서","운동을 하려고"],"c":"길이 막히니까","ex":"Pria tersebut menyarankan naik kereta bawah tanah karena jalanan macet (차가 막히니까).","romaji":"Namjaga jihacheoreul taryeoneun iyuneun mueosimnikka?","ch":22},{"id":"l_22_04","q":"다음 중 들은 내용과 일치하는 표지판은 무엇입니까?","audio":"여러분, 안내 말씀 드립니다. 우리 미술관 안에서는 사진 촬영이 금지되어 있습니다. 사진을 찍으면 안 됩니다. 그리고 음식물 반입도 안 되니까 밖에서 다 드시고 들어오십시오. 마지막으로 큰 소리로 떠들면 다른 사람들에게 방해가 됩니다. 조용히 관람해 주세요.","a":["주차 금지","사진 촬영 금지","휴대전화 사용 금지","접근 금지"],"c":"사진 촬영 금지","ex":"Pengumuman di galeri seni melarang pengambilan foto (사진 촬영 금지), membawa makanan, dan berisik.","romaji":"Daeum jung deureun naeyonggwa ilchihaneun pyojipaneun mueosimnikka?","ch":22},{"id":"l_22_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 투안 씨, 극장 안에서 담배를 피우면 안 돼요. 남: 아, 그래요? 몰랐어요. 죄송합니다. 여: 여기는 금연 구역이니까 담배를 피우고 싶으면 건물 밖으로 나가야 돼요. 남: 네, 알겠습니다. 지금 바로 나갈게요. 여: 그리고 극장 안에서는 음식물도 가지고 들어오면 안 돼요.","a":["남자는 극장 안에서 담배를 피웠습니다.","극장 안은 담배를 피울 수 없는 곳입니다.","남자는 건물 밖에서 음식을 먹어야 합니다.","극장 안에서 음식을 먹어도 됩니다."],"c":"극장 안에서 음식을 먹어도 됩니다.","ex":"Wanita tersebut mengatakan tidak boleh membawa makanan ke dalam bioskop (음식물도 가지고 들어오면 안 돼요), sehingga opsi D salah.","romaji":"Daehwa naeyonggwa dareun geoseul goreusipsio.","ch":22},{"id":"l_23_01","q":"여자는 한국 친구 집에 갈 때 무엇을 물어봤습니까?","audio":"여: 지훈 씨, 제가 한국 친구 집에 초대를 받았는데 어른이 계시는 집이라서 좀 걱정돼요. 어른들께 어떤 선물을 드리면 좋을까요?","a":["밥을 먹는 방법","드려야 할 선물","신발을 신는 방법","자리를 양보하는 방법"],"c":"드려야 할 선물","ex":"Pembicara wanita bertanya tentang hadiah apa yang sebaiknya diberikan kepada orang tua di rumah temannya.","romaji":"Yeojaneun Hanguk chingu jibe gal ttae mueoseul mureobwasseumnikka?","ch":23},{"id":"l_23_02","q":"어른께 물건을 드릴 때 어떻게 해야 합니까?","audio":"한국에서는 어른께 물건을 드릴 때 두 손으로 드려야 합니다. 한 손으로 드리면 예의가 아닙니다.","a":["한 손으로 드립니다","두 손으로 드립니다","던져서 드립니다","허리를 숙이지 않습니다"],"c":"두 손으로 드립니다","ex":"Etika di Korea saat memberikan barang kepada orang tua adalah menggunakan dua tangan (두 손으로 드려야 합니다).","romaji":"Eoreunkke mulgeoneul deuril ttae eotteoke haeya hamnikka?","ch":23},{"id":"l_23_03","q":"지하철에서 해야 할 행동으로 알맞은 것은 무엇입니까?","audio":"지하철이나 버스에서 어른을 뵈면 자리를 양보해야 합니다. 자리를 차지하고 앉아 있으면 안 됩니다.","a":["자리를 양보합니다","큰 소리로 전화합니다","신발을 벗습니다","음식을 먹습니다"],"c":"자리를 양보합니다","ex":"Di transportasi umum, seseorang harus memberikan kursi (자리를 양보하다) kepada orang tua.","romaji":"Jihacheoreoseo haeya hal haengdong-euro almajeun geoseun mueosimnikka?","ch":23},{"id":"l_23_04","q":"들은 내용과 다른 것을 고르십시오.","audio":"한국의 식사 예절에 대해 알려 드릴게요. 어른과 함께 식사할 때는 어른이 먼저 숟가락을 드실 때까지 기다려야 합니다. 그리고 밥그릇을 들고 먹으면 안 됩니다. 식사가 끝난 후에는 숟가락과 젓가락을 식탁 위에 놓으면 됩니다.","a":["어른보다 먼저 밥을 먹으면 안 됩니다.","밥그릇을 들고 식사를 해야 합니다.","식사 후 수저를 식탁 위에 놓습니다.","어른이 식사를 시작할 때까지 기다립니다."],"c":"밥그릇을 들고 식사를 해야 합니다.","ex":"Dalam audio disebutkan tidak boleh mengangkat mangkuk nasi saat makan (밥그릇을 들고 먹으면 안 됩니다).","romaji":"Deureun naeyonggwa dareun geoseul goreusipsio.","ch":23},{"id":"l_23_05","q":"남자의 아버지는 어떤 분입니까?","audio":"가: 투안 씨, 이 사진에 있는 분이 아버지세요? 나: 네, 우리 아버지예요. 가: 아버지가 키가 정말 크시네요. 나: 네, 키가 크고 아주 멋있으세요. 지금은 고향에서 사세요. 작년에 한국에 오셨을 때 같이 여행도 했어요.","a":["지금 한국에 살고 계십니다.","키가 작으신 편입니다.","지금 고향에 살고 계십니다.","작년에 아들과 여행을 안 했습니다."],"c":"지금 고향에 살고 계십니다.","ex":"Tuan mengatakan ayahnya sekarang tinggal di kampung halaman (지금은 고향에서 사세요).","romaji":"Namjayi abeojineun eotteon bun-imnikka?","ch":23},{"id":"l_24_01","q":"여자는 한국어를 어떻게 공부합니까?","audio":"여: 저는 한국 영화 보는 것을 좋아해서 한국 영화를 보면서 공부해요. 수피카 씨도 좋아하는 것을 하면서 공부해 보세요.","a":["학원에 다닙니다","사전만 찾습니다","영화를 보면서 공부합니다","친구와 이야기만 합니다"],"c":"영화를 보면서 공부합니다","ex":"Wanita tersebut menjelaskan bahwa ia belajar bahasa Korea sambil menonton film.","romaji":"Yeojaneun hangugeoreul eotteoke gongbu-hamnikka?","ch":24},{"id":"l_24_02","q":"한국어 수업이 언제 있습니까?","audio":"우리 센터에서는 외국인 근로자를 위한 한국어 수업이 있습니다. 수업은 매주 일요일 오후 3시부터 5시까지입니다.","a":["토요일 오전","토요일 오후","일요일 오전","일요일 오후"],"c":"일요일 오후","ex":"Kelas bahasa Korea diadakan setiap hari Minggu sore (일요일 오후).","romaji":"Hangugeo sueobi eonje isseumnikka?","ch":24},{"id":"l_24_03","q":"남자는 왜 자동차 정비 교육을 받으려고 합니까?","audio":"저는 나중에 고향에 돌아가서 일을 구할 때 도움이 될 것 같아서 자동차 정비 교육을 신청했어요. 수업이 아주 재미있어요.","a":["한국 영화가 좋아서","취업에 도움이 될 것 같아서","한국 친구를 만나려고","시간이 너무 많아서"],"c":"취업에 도움이 될 것 같아서","ex":"Tuan mengambil pelatihan servis mobil karena menganggap itu akan membantu saat mencari kerja di kampung halaman nanti.","romaji":"Namjaneun wae jadongcha jeongbi gyoyugeul badeuryeogo hamnikka?","ch":24},{"id":"l_24_04","q":"대화 내용으로 알 수 있는 것은 무엇입니까?","audio":"남: 흐엉 씨, 한국어 공부하기가 어때요? 여: 한국어 단어가 너무 어려워서 그러는데 공부하기가 쉽지 않아요. 남: 그래요? 그럼 모르는 단어는 사전을 찾으면서 공부해 보세요. 그리고 인터넷 강의를 듣는 것도 도움이 돼요. 여: 고마워요. 저도 인터넷 강의를 한번 들어 볼게요.","a":["여자는 한국어 공부가 아주 쉽습니다.","남자는 여자에게 사전을 찾으라고 합니다.","여자는 이미 인터넷 강의를 듣고 있습니다.","두 사람은 지금 영화관에 있습니다."],"c":"남자는 여자에게 사전을 찾으라고 합니다.","ex":"Pria menyarankan untuk belajar sambil mencari kata sulit di kamus (사전을 찾으면서 공부해 보세요).","romaji":"Daehwa naeyong-euro al su itneun geoseun mueosimnikka?","ch":24},{"id":"l_24_05","q":"교육 프로그램 신청 순서로 맞는 것을 고르십시오.","audio":"교육 프로그램을 신청하려면 먼저 홈페이지에서 어떤 수업이 있는지 찾아보세요. 그 다음에 수업 시간과 장소를 확인하고 신청 버튼을 누르세요. 개인 정보를 입력하고 나서 '보내기'를 클릭하면 신청이 끝납니다. 나중에 이메일로 결과를 확인할 수 있습니다.","a":["정보 입력 - 수업 검색 - 장소 확인","수업 검색 - 장소 확인 - 정보 입력","이메일 확인 - 신청 버튼 클릭 - 수업 검색","신청 버튼 클릭 - 이메일 확인 - 정보 입력"],"c":"수업 검색 - 장소 확인 - 정보 입력","ex":"Urutan pendaftaran adalah mencari kelas (찾아보세요), cek waktu/tempat (확인하고), lalu masukkan data diri (정보를 입력).","romaji":"Gyoyuk peurogeuraem sincheong sunseoro manneun geoseul goreusipsio.","ch":24},{"id":"l_25_01","q":"리리 씨는 일요일에 무엇을 합니까?","audio":"여: 미영 씨, 미안해요. 일요일에는 제가 교회에 가야 돼요. 일요일마다 교회에 가서 예배를 드리거든요.","a":["쇼핑을 합니다","영화를 봅니다","교회에 갑니다","회사에 갑니다"],"c":"교회에 갑니다","ex":"Riri (wanita) mengatakan setiap hari Minggu ia harus pergi ke gereja untuk beribadah.","romaji":"Riri ssineun iryo-ire mueoseul hamnikka?","ch":25},{"id":"l_25_02","q":"아딧 씨는 종교가 무엇입니까?","audio":"아딧 씨는 인도네시아 사람입니다. 하루에 다섯 번씩 기도를 드립니다. 시간이 나면 이태원에 있는 이슬람 사원에 갑니다.","a":["불교","기독교","천주교","이슬람교"],"c":"이슬람교","ex":"Adit berdoa 5 kali sehari dan pergi ke masjid (이슬람 사원), maka agamanya adalah Islam.","romaji":"Adit ssineun jonggyoga mueosimnikka?","ch":25},{"id":"l_25_03","q":"지하철은 몇 분마다 옵니까?","audio":"가: 여기에서 시청에 가려면 지하철이 자주 와요? 나: 네, 출퇴근 시간에는 사람이 많아서 삼 분마다 와요. 잠시만 기다리세요.","a":["1분마다","3분마다","5분마다","10분마다"],"c":"3분마다","ex":"Kereta bawah tanah datang setiap 3 menit (삼 분마다) pada jam sibuk.","romaji":"Jihacheoreun myeot bun-mada omnikka?","ch":25},{"id":"l_25_04","q":"들은 내용과 일치하지 않는 것을 고르십시오.","audio":"가: 미영 씨는 종교가 있어요? 나: 부모님이 불교 신자라서 저도 어릴 때는 절에 다녔어요. 그런데 요즘은 바빠서 잘 안 가요. 가: 그렇군요. 저는 일요일마다 성당에 가서 미사를 드려요. 성당에 가면 마음이 참 편안해져요.","a":["여자의 부모님은 불교를 믿습니다.","남자는 일요일마다 성당에 갑니다.","여자는 요즘도 절에 자주 다닙니다.","남자는 성당에 가면 기분이 좋아집니다."],"c":"여자는 요즘도 절에 자주 다닙니다.","ex":"Miyeong (wanita) mengatakan dulu sering ke kuil tapi sekarang jarang pergi karena sibuk (요즘은 바빠서 잘 안 가요).","romaji":"Deureun naeyonggwa ilchihaji anneun geoseul goreusipsio.","ch":25},{"id":"l_25_05","q":"여자의 소원은 무엇입니까?","audio":"저는 한국에서 일하면서 돈을 많이 벌었으면 좋겠어요. 그래서 고향에 있는 가족들에게 큰 집을 사 주고 싶어요. 그리고 우리 가족 모두가 아프지 않고 건강하게 살았으면 좋겠어요. 내년에는 꼭 고향에 가서 가족들을 만나고 싶어요.","a":["돈을 많이 버는 것","혼자 한국에서 사는 것","일을 그만두는 것","내년에 여행을 안 가는 것"],"c":"돈을 많이 버는 것","ex":"Wanita tersebut berharap bisa menghasilkan banyak uang (돈을 많이 벌었으면 좋겠어요) untuk keluarganya.","romaji":"Yeojayi sowoneun mueosimnikka?","ch":25},{"id":"l_26_01","q":"바루 씨는 어디가 아픕니까?","audio":"약사: 어떻게 오셨어요? 바루: 머리가 아파서 왔어요. 약사: 언제부터 아프셨어요? 바루: 어젯밤부터요.","a":["배가 아픕니다","머리가 아픕니다","다리가 아픕니다","이가 아픕니다"],"c":"머리가 아픕니다","ex":"Dalam percakapan, Baru menjawab \"머리가 아파서 왔어요\" yang berarti dia datang karena sakit kepala.","romaji":"Baru ssineun eodiga apeumnikka? / Yaksa: Eotteoke osyeosseoyo? Baru: Meoriga apaseo wasseoyo. Yaksa: Eonjebuteo apeusyeosseoyo? Baru: Eojetbambuteoyo.","ch":26},{"id":"l_26_02","q":"여자는 오늘 무엇을 먹으면 안 됩니까?","audio":"모니카 씨, 오늘 아침부터 배가 많이 아파요? 그럼 이 약을 드세요. 그리고 오늘은 유제품은 먹지 마세요.","a":["고기","과일","우유","채소"],"c":"우유","ex":"Apoteker menyarankan agar Monika tidak mengonsumsi produk olahan susu (유제품) seperti susu.","romaji":"Yeojaneun oneul mueoseul meogeumyeon an doemnikka?","ch":26},{"id":"l_26_03","q":"이 약은 언제 먹어야 합니까?","audio":"가: 이 약은 언제 먹어야 돼요? 나: 밥을 먹은 후에 드세요. 하루에 세 번 드시면 됩니다.","a":["식사 전에","식사 후에","잠자기 전에","아침에만"],"c":"식사 후에","ex":"Instruksi dalam audio menyatakan obat harus diminum setelah makan (밥을 먹은 후에).","romaji":"I yageun eonje meogeoya hamnikka?","ch":26},{"id":"l_26_04","q":"바루 씨가 머리가 아픈 이유는 무엇입니까?","audio":"약사: 언제부터 아프셨어요? 바루: 어젯밤부터요. 어제 저녁에 회식이 있어서 술을 좀 마셨어요. 약사: 아, 술 때문에 그런 것 같네요. 밥을 먹은 후에 이 약을 드세요. 바루: 네, 감사합니다.","a":["어제 일을 많이 해서","어제 술을 마셔서","아침을 안 먹어서","감기에 걸려서"],"c":"어제 술을 마셔서","ex":"Apoteker menyimpulkan Baru sakit kepala karena minum alkohol (술 때문에) saat acara makan malam kantor kemarin.","romaji":"Baru ssiga meoriga apeun iyuneun mueosimnikka?","ch":26},{"id":"l_26_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"반장님, 저 모니카예요. 오늘 너무 아파서 회사에 못 갑니다. 어제 저녁부터 배가 아프고 계속 설사를 했어요. 어제 약국에서 약을 사 먹었는데 아직도 아파요. 오늘 아침에는 열도 나서 오늘은 집에서 쉬려고 해요. 죄송합니다.","a":["모니카 씨는 오늘 회사에 갔습니다.","모니카 씨는 어제 약을 안 먹었습니다.","모니카 씨는 배가 아프고 열이 납니다.","모니카 씨는 오늘 약국에 갈 겁니다."],"c":"모니카 씨는 배가 아프고 열이 납니다.","ex":"Monika sakit perut, diare sejak kemarin, dan pagi ini juga demam (열도 나서), sehingga dia izin tidak masuk kerja.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":26},{"id":"l_27_01","q":"투안 씨는 어디가 아픕니까?","audio":"리한: 투안 씨, 걷는 게 왜 그래요? 투안: 발목이 좀 아파요. 어제 계단에서 넘어졌거든요.","a":["손목","발목","허리","어깨"],"c":"발목","ex":"Tuan mengatakan pergelangan kakinya (발목) sakit karena jatuh di tangga kemarin.","romaji":"Tuan ssineun eodiga apeumnikka?","ch":27},{"id":"l_27_02","q":"남자는 어디에 가야 합니까?","audio":"가: 목이 너무 아파요. 나: 목이 아프면 이비인후과에 가 보세요. 저기 지하철역 근처에 있어요.","a":["치과","안과","내과","이비인후과"],"c":"이비인후과","ex":"Untuk sakit tenggorokan (목), disarankan pergi ke klinik THT (이비인후과).","romaji":"Namjaneun eodie gaya hamnikka?","ch":27},{"id":"l_27_03","q":"남자는 무엇을 했습니까?","audio":"어제 요리를 하다가 손을 데었어요. 그래서 연고를 바르고 밴드를 붙였어요.","a":["주사를 맞았습니다","붕대를 감았습니다","밴드를 붙였습니다","수술을 했습니다"],"c":"밴드를 붙였습니다","ex":"Pria tersebut mengoleskan salep dan menempelkan plester (밴드를 붙였어요) setelah tangannya terkena panas saat memasak.","romaji":"Namjaneun mueoseul haesseumnikka?","ch":27},{"id":"l_27_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 어떻게 오셨습니까? 남: 넘어져서 발목을 삐었어요. 여: 어디 봅시다. 여기가 아픕니까? 남: 아! 네. 여: 발목에 파스를 붙이시고 많이 걷지 마세요. 그리고 집에서 찜질을 하셔야 됩니다. 남: 네, 알겠습니다.","a":["남자는 발목을 다쳤습니다.","남자는 많이 걸어야 합니다.","남자는 집에서 찜질을 해야 합니다.","여자는 남자에게 파스를 주었습니다."],"c":"남자는 많이 걸어야 합니다.","ex":"Petugas medis melarang pria tersebut banyak berjalan (많이 걷지 마세요), sehingga opsi B salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":27},{"id":"l_27_05","q":"여자는 대화 후에 무엇을 할 것입니까?","audio":"남: 수지 씨, 근무 시간에 어디에 갔다 왔어요? 여: 죄송해요, 반장님. 점심 먹고 속이 너무 안 좋아서 휴게실에서 좀 쉬었어요. 남: 많이 아프면 일찍 들어가서 약 먹고 좀 쉬도록 해요. 여: 네, 반장님. 그렇게 할게요. 감사합니다.","a":["계속 일을 합니다.","점심을 먹으러 갑니다.","집에 가서 쉽니다.","병원에 가서 진찰을 받습니다."],"c":"집에 가서 쉽니다.","ex":"Karena perutnya tidak enak, mandor mengizinkan Su-ji pulang lebih awal untuk istirahat, dan Su-ji menyetujuinya.","romaji":"Yeojaneun daehwa hue mueoseul hal geosimnikka?","ch":27},{"id":"l_28_01","q":"리한 씨는 왜 은행에 왔습니까?","audio":"은행원: 어떻게 오셨습니까? 리한: 통장을 만들려고 왔어요. 은행원: 신분증을 가지고 오셨습니까?","a":["돈을 찾으려고","환전하려고","통장을 만들려고","송금하려고"],"c":"통장을 만들려고","ex":"Rihan secara eksplisit menyatakan tujuannya adalah membuat buku tabungan atau rekening (통장을 만들려고).","romaji":"Rihan ssineun wae eunhenge wasseumnikka?","ch":28},{"id":"l_28_02","q":"남자는 오늘 무엇을 합니까?","audio":"오늘은 월급날이에요. 그래서 은행에 가서 고향으로 돈을 보내려고 해요. 송금 수수료가 적은 은행을 찾고 있어요.","a":["가입을 합니다","송금을 합니다","출금을 합니다","조회를 합니다"],"c":"송금을 합니다","ex":"Karena hari ini hari gajian, pria tersebut ingin mengirim uang ke kampung halaman (송금).","romaji":"Namjaneun oneul mueoseul hamnikka?","ch":28},{"id":"l_28_03","q":"환전을 하려면 어디에 가야 합니까?","audio":"가: 한국 돈을 베트남 돈으로 바꾸고 싶어요. 나: 환전을 하려면 회사 앞에 있는 은행에 가 보세요. 저도 거기에서 했어요.","a":["병원","우체국","도서관","은행"],"c":"은행","ex":"Disarankan pergi ke bank (은행) untuk menukar mata uang (환전).","romaji":"Hwanjeoneul haryeomeun eodie gaya hamnikka?","ch":28},{"id":"l_28_04","q":"은행에서 통장을 만들 때 필요한 것은 무엇입니까?","audio":"은행에 가서 통장을 만들려면 신분증이 필요합니다. 외국인은 외국인등록증이나 여권이 있으면 됩니다. 신분증을 보여주고 신청서를 씁니다. 그리고 서명을 하면 통장이 나옵니다.","a":["휴대 전화","신용카드","신분증","사진기"],"c":"신분증","ex":"Untuk membuat rekening, diperlukan kartu identitas (신분증) seperti kartu registrasi asing atau paspor.","romaji":"Eunhengeseo tongjangeul mandeul ttae piryohan geoseun mueosimnikka?","ch":28},{"id":"l_28_05","q":"오늘은 무슨 요일입니까?","audio":"여: 은행에요? 오늘은 일요일인데 고향으로 송금할 수 있어요? 남: 네. 우리 동네 은행은 일하는 외국인들이 많아서 일요일에도 문을 열어요. 그래서 지금 가려고 해요.","a":["월요일","토요일","일요일","금요일"],"c":"일요일","ex":"Wanita tersebut mengonfirmasi bahwa hari ini adalah hari Minggu (일요일) dan bertanya apakah bank tetap buka.","romaji":"Oneureun museun yoirimnikka?","ch":28},{"id":"l_29_01","q":"모니카 씨는 무엇을 보냅니까?","audio":"우체국 직원: 어떻게 오셨습니까? 모니카: 엽서를 보내고 싶은데요. 필리핀으로 보낼 겁니다.","a":["편지","소포","엽서","카드"],"c":"엽서","ex":"Monika ingin mengirim kartu pos (엽서) ke Filipina.","romaji":"Monika ssineun mueoseul bonemnikka?","ch":29},{"id":"l_29_02","q":"소포를 보내려면 상자를 어디에 놓아야 합니까?","audio":"베트남으로 소포를 보내려고 하는데요. 네, 그럼 상자를 저울에 올려놓으십시오. 무게를 재야 합니다.","a":["책상 위","저울 위","의자 위","바닥 위"],"c":"저울 위","ex":"Petugas meminta agar kotak diletakkan di atas timbangan (저울에 올려놓으십시오) untuk diukur beratnya.","romaji":"Soporeul boneryeomyeon sangjareul eodie noaya hamnikka?","ch":29},{"id":"l_29_03","q":"항공편으로 보내면 시간이 얼마나 걸립니까?","audio":"베트남까지 얼마나 걸릴까요? 배편은 한두 달 정도 걸리고 항공편은 열흘에서 이 주 정도 걸립니다.","a":["한두 달","삼 일","오 일","열흘에서 이 주"],"c":"열흘에서 이 주","ex":"Pengiriman melalui pesawat (항공편) memakan waktu 10 hari sampai 2 minggu (열흘에서 이 주).","romaji":"Hanggongpyeoneuro bonemyeon sigani eolmana geollimnikka?","ch":29},{"id":"l_29_04","q":"남자가 우체국에 온 이유는 무엇입니까?","audio":"여: 어떻게 오셨어요? 남: 중국으로 소포를 보내려고 합니다. 여: 안에 무엇이 있습니까? 남: 옷하고 책이 있어요. 여: 그럼 여기 저울 위에 올려놓으세요.","a":["소포를 받으려고","소포를 보내려고","친구를 만나려고","옷을 사려고"],"c":"소포를 보내려고","ex":"Pria tersebut datang untuk mengirim paket (소포를 보내려고) berisi pakaian dan buku ke Cina.","romaji":"Namjaga ucheguge on iyuneun mueosimnikka?","ch":29},{"id":"l_29_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"여: 베트남으로 엽서를 보내려고 하는데 얼마나 걸릴까요? 남: 국제 특급은 사 일 정도 걸리고 일반 우편은 칠 일에서 십 일 정도 걸려요. 여: 그럼 국제 특급으로 할게요. 남: 네, 여기에 주소를 쓰십시오.","a":["국제 특급은 칠 일이 걸립니다.","일반 우편이 국제 특급보다 빠릅니다.","여자는 일반 우편으로 보낼 겁니다.","국제 특급은 사 일 정도 걸립니다."],"c":"국제 특급은 사 일 정도 걸립니다.","ex":"Berdasarkan audio, EMS (국제 특급) memakan waktu sekitar 4 hari, sedangkan pos biasa 7-10 hari.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":29},{"id":"l_30_01","q":"남자는 왜 센터에 전화했습니까?","audio":"리한: 여보세요. 거기 외국인력지원센터지요? 태권도를 배우고 싶은데 수업을 들을 수 있어요?","a":["태권도를 배우고 싶어서","한국 음식을 만들고 싶어서","친구를 찾고 싶어서","병원을 예약하고 싶어서"],"c":"태권도를 배우고 싶어서","ex":"Rihan menelepon karena ingin belajar taekwondo (태권도를 배우고 싶어서).","romaji":"Namjaneun wae senteoe jeonwhahaesseumnikka?","ch":30},{"id":"l_30_02","q":"태권도 수업은 무슨 요일에 있습니까?","audio":"네, 우리 센터에서는 매주 일요일에 태권도 수업이 있어요. 전혀 할 수 없어도 괜찮으니까 오셔서 상담을 받아 보세요.","a":["토요일","일요일","월요일","금요일"],"c":"일요일","ex":"Kelas taekwondo diadakan setiap hari Minggu (일요일).","romaji":"Taegwondo sueobeun museun yoire isseumnikka?","ch":30},{"id":"l_30_03","q":"교육을 신청하려면 무엇을 해야 합니까?","audio":"가: 한국어 교육을 신청하려고 하는데 어떻게 해야 돼요? 나: 그럼 먼저 이 신청서를 쓰고 잠깐만 기다리세요.","a":["돈을 냅니다","신청서를 씁니다","전화를 합니다","사진을 찍습니다"],"c":"신청서를 씁니다","ex":"Untuk mendaftar, langkah pertamanya adalah mengisi formulir pendaftaran (신청서를 쓰고).","romaji":"Gyoyugeul sincheongharyeomyeon mueoseul haeya hamnikka?","ch":30},{"id":"l_30_04","q":"외국인력지원센터에서 할 수 없는 것은 무엇입니까?","audio":"안녕하세요. 우리 센터에서는 외국인 근로자들을 위해 다양한 프로그램을 운영합니다. 한국어와 컴퓨터를 배울 수 있고 태권도 수업도 있습니다. 또한 무료 진료와 법률 상담도 받을 수 있으니 많이 이용해 주세요.","a":["컴퓨터 배우기","법률 상담 받기","비행기 표 사기","무료 진료 받기"],"c":"비행기 표 사기","ex":"Pusat bantuan menyediakan program bahasa, komputer, taekwondo, medis, dan hukum, tetapi tidak disebutkan layanan pembelian tiket pesawat.","romaji":"Oegugin-illyeok-jiwon-senteo-eseo hal su eomneun geoseun mueosimnikka?","ch":30},{"id":"l_30_05","q":"무료 진료는 언제 받을 수 있습니까?","audio":"안내 말씀 드립니다. 우리 센터에서는 매월 둘째 일요일 오후 두 시에 무료 진료를 실시합니다. 내과, 치과, 한방 진료를 받을 수 있으니 아픈 분들은 회의실로 오시기 바랍니다. 감사합니다.","a":["매주 화요일 오전 11시","매월 둘째 일요일 오후 2시","매일 오후 2시","매주 일요일 오전 10시"],"c":"매월 둘째 일요일 오후 2시","ex":"Pengumuman menyatakan pemeriksaan gratis dilakukan setiap hari Minggu kedua setiap bulan jam 2 siang (매월 둘째 일요일 오후 두 시).","romaji":"Muryo jinryoneun eonje badeul su isseumnikka?","ch":30},{"id":"l_31_01","q":"바루 씨의 고향 날씨는 어떠합니까?","audio":"바루 씨, 밖을 보세요. 지금 눈이 와요. 우리 고향은 일 년 내내 더워요. 그래서 눈이 오지 않아요. 정말 신기해요.","a":["일 년 내내 따뜻합니다","일 년 내내 덥습니다","겨울에 눈이 많이 옵니다","서울보다 기온이 낮습니다"],"c":"일 년 내내 덥습니다","ex":"Dalam audio, Baru menyatakan bahwa kampung halamannya panas sepanjang tahun (일 년 내내 더워요) sehingga tidak turun salju.","romaji":"Baru ssiyi gohyang nalssineun eotteohamnikka?","ch":31},{"id":"l_31_02","q":"남자의 고향은 서울보다 무엇이 적습니까?","audio":"우리 고향은 서울보다 인구도 적고 조용해요. 그래서 처음 서울에 왔을 때는 사람이 너무 많아서 깜짝 놀랐어요.","a":["인구","건물","자동차","공기"],"c":"인구","ex":"Pembicara menyebutkan bahwa kampung halamannya memiliki populasi yang lebih sedikit (인구도 적고) dibandingkan Seoul.","romaji":"Namjayi gohyangeun Seoul-boda mueosi jeokseumnikka?","ch":31},{"id":"l_31_03","q":"오늘 기온은 몇 도까지 올라갑니까?","audio":"오늘 날씨가 어때요? 어제보다 시원해요. 최고기온은 22도이고 최저기온은 15도예요.","a":["15도","22도","25도","30도"],"c":"22도","ex":"Audio menyatakan suhu tertinggi (최고기온) hari ini adalah 22 derajat.","romaji":"Oneul gioneun myeot dokkaji ollagamnikka?","ch":31},{"id":"l_31_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"택시 기사: 어디에서 오셨어요? 칸: 캄보디아에서 왔어요. 기사: 아, 저도 여행을 가 봤는데 정말 좋았어요. 공기도 맑고 조용하고요. 칸: 네, 우리 고향은 인구도 적고 한적해요. 서울은 사람이 너무 많아서 복잡한 것 같아요.","a":["칸 씨는 캄보디아 사람입니다.","칸 씨의 고향은 공기가 맑습니다.","서울은 캄보디아보다 인구가 많습니다.","택시 기사는 캄보디아에 안 가 봤습니다."],"c":"택시 기사는 캄보디아에 안 가 봤습니다.","ex":"Sopir taksi mengatakan dia pernah berwisata ke sana (저도 여행을 가 봤는데), sehingga opsi D salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":31},{"id":"l_31_05","q":"보라카이 날씨에 대한 설명으로 맞는 것은 무엇입니까?","audio":"보라카이는 일 년 내내 따뜻합니다. 평균 기온은 25도 정도이고 영하로 내려가는 날이 없습니다. 7월과 8월에는 비가 많이 오지만 11월부터는 습도가 낮아서 여행하기에 아주 좋습니다.","a":["1월에는 눈이 많이 옵니다.","일 년 내내 습도가 높습니다.","7월에는 비가 많이 옵니다.","평균 기온이 영하입니다."],"c":"7월에는 비가 많이 옵니다.","ex":"Audio menyatakan pada bulan Juli dan Agustus hujan turun deras (7월과 8월에는 비가 많이 오지만).","romaji":"Borakai nalssie daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":31},{"id":"l_32_01","q":"한국 사람들은 여름에 왜 삼계탕을 먹습니까?","audio":"날씨가 더운데 왜 뜨거운 삼계탕을 먹어요? 여름에 뜨거운 음식을 먹으면 몸이 따뜻해져서 더위를 이길 수 있어요.","a":["요리하기 쉬워서","맛이 달기 때문에","더위를 이기기 위해서","가격이 저렴해서"],"c":"더위를 이기기 위해서","ex":"Memakan makanan panas di musim panas membantu menghangatkan tubuh agar bisa mengalahkan hawa panas (더위를 이길 수 있어요).","romaji":"Hanguk saramdeureun yeoreume wae samgyetangeul meokseumnikka?","ch":32},{"id":"l_32_02","q":"김치찌개를 만들 때 마지막에 무엇을 넣습니까?","audio":"먼저 김치하고 돼지고기를 볶으세요. 그 다음에 물을 넣고 끓이세요. 물이 끓으면 양파와 파를 넣으세요.","a":["돼지고기","김치","식용유","양파와 파"],"c":"양파와 파","ex":"Berdasarkan cara masak, bawang bombay dan daun bawang (양파와 파) dimasukkan setelah air mendidih.","romaji":"Gimchijjigaereul mandeul ttae majimage mueoseul neokseumnikka?","ch":32},{"id":"l_32_03","q":"두 사람은 무엇을 주문했습니까?","audio":"어느 식당에 갈까요? 저기 사람이 많은 식당에 들어가요. 그럼 불고기만 2인분 주세요. 공깃밥 두 그릇하고요.","a":["삼계탕 2인분","김치찌개 2인분","불고기 2인분과 밥","냉면 2그릇"],"c":"불고기 2인분과 밥","ex":"Pria tersebut memesan 2 porsi bulgogi dan 2 mangkuk nasi (불고기 2인분... 공깃밥 두 그릇).","romaji":"Du sarameun mueoseul jumun-haesseumnikka?","ch":32},{"id":"l_32_04","q":"한국의 식사 예절에 대한 설명으로 맞는 것은 무엇입니까?","audio":"한국 사람들은 식사를 할 때 밥과 함께 국이나 찌개, 그리고 여러 가지 반찬을 같이 먹어요. 이때 밥하고 국, 찌개는 숟가락으로 먹고 반찬은 젓가락으로 먹어요. 숟가락과 젓가락을 모두 사용해요.","a":["국은 젓가락으로 먹습니다.","밥을 먹을 때 숟가락을 사용합니다.","반찬은 숟가락으로만 먹습니다.","빵과 우유를 주로 먹습니다."],"c":"밥을 먹을 때 숟가락을 사용합니다.","ex":"Nasi, sup, dan jjigae dimakan menggunakan sendok (숟가락으로 먹고).","romaji":"Hangukui siksa yejeore daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":32},{"id":"l_32_05","q":"김치찌개 조리 방법으로 일치하지 않는 것은 무엇입니까?","audio":"김치찌개를 맛있게 끓이는 방법을 알려 줄게요. 먼저 김치와 돼지고기를 적당하게 써세요. 냄비에 김치와 고기를 넣고 식용유와 함께 볶으세요. 고기가 익으면 물을 넣고 끓이세요. 마지막에 양파와 파를 넣으면 끝납니다.","a":["고기를 먼저 볶습니다.","물이 끓기 전에 양파를 넣습니다.","김치를 적당한 크기로 썹니다.","냄비에 물을 넣고 끓입니다."],"c":"물이 끓기 전에 양파를 넣습니다.","ex":"Bawang bombay dimasukkan setelah air mendidih (물이 끓으면), bukan sebelum, sehingga opsi B salah.","romaji":"Gimchijjigae jori bangbeop-euro ilchihaji anneun geoseun mueosimnikka?","ch":32},{"id":"l_33_01","q":"남자는 이번 명절에 무엇을 할 것입니까?","audio":"지훈 씨는 이번 명절에 뭐 할 거예요? 해마다 고향에 다녀왔는데 이번에는 집에 있으려고요. 일도 많고 연휴도 짧아서 못 갈 것 같아요.","a":["고향에 갑니다","집에서 쉽니다","친구를 만납니다","여행을 갑니다"],"c":"집에서 쉽니다","ex":"Karena pekerjaan banyak dan libur singkat, Ji-hoon memutuskan untuk tetap di rumah (집에 있으려고요).","romaji":"Namjaneun ibon myeongjeore mueoseul hal geosimnikka?","ch":33},{"id":"l_33_02","q":"설날에 하는 행동이 아닌 것은 무엇입니까?","audio":"설날 아침에는 한복을 입고 어른들께 세배를 해요. 그리고 가족들과 같이 떡국을 먹어요. 아이들은 세뱃돈을 받기도 해요.","a":["세배를 합니다","떡국을 먹습니다","한복을 입습니다","송편을 빚습니다"],"c":"송편을 빚습니다","ex":"Membuat Songpyeon (송편) biasanya dilakukan saat Chuseok, sedangkan audio hanya menyebutkan Sebae, Tteokguk, dan Hanbok untuk Seollal.","romaji":"Seollare haneun haengdong-i anin geoseun mueosimnikka?","ch":33},{"id":"l_33_03","q":"여자는 추석 연휴에 어디에 가려고 합니까?","audio":"수피카 씨, 추석 연휴에 뭐 할 거예요? 저는 친구들하고 경복궁에 가려고 해요. 거기에서 여러 가지 행사를 하거든요.","a":["고향 집","경복궁","박물관","놀이공원"],"c":"경복궁","ex":"Heong berencana pergi ke Istana Gyeongbokgung bersama teman-temannya.","romaji":"Yeojaneun Chuseok yeonhue eodie garyeogo hamnikka?","ch":33},{"id":"l_33_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"여: 지훈 씨, 이번 명절에 고향에 안 가요? 남: 네, 이번 연휴는 너무 짧아서 그냥 집에 있기로 했어요. 여: 아쉽겠네요. 남: 괜찮아요. 친구들하고 같이 한국 음식을 만들어 먹을 거예요. 흐엉 씨는요? 여: 저는 고향에 다녀올 거예요.","a":["두 사람은 같이 고향에 갑니다.","남자는 이번 연휴에 일을 합니다.","여자는 이번 명절에 고향에 갑니다.","남자는 혼자서 떡국을 먹을 겁니다."],"c":"여자는 이번 명절에 고향에 갑니다.","ex":"Wanita (Heong) mengatakan dia akan pergi ke kampung halaman (저는 고향에 다녀올 거예요).","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":33},{"id":"l_33_05","q":"한국의 추석에 대한 설명으로 맞는 것은 무엇입니까?","audio":"추석은 한국의 큰 명절 중 하나입니다. 추석에는 고향에 내려가는 사람들이 많아서 기차 표를 미리 사야 합니다. 가족들이 모여서 햇곡식으로 만든 음식을 먹고 송편을 빚습니다. 밤에는 보름달을 보면서 소원을 빕니다.","a":["추석에는 떡국을 꼭 먹어야 합니다.","추석에는 달을 보며 소원을 빕니다.","추석 연휴에는 기차 표를 사기 쉽습니다.","추석은 한국에서 가장 추운 날입니다."],"c":"추석에는 달을 보며 소원을 빕니다.","ex":"Saat Chuseok, orang-orang melihat bulan purnama dan berdoa/meminta harapan (보름달을 보면서 소원을 빕니다).","romaji":"Hangukui Chuseok-e daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":33},{"id":"l_34_01","q":"여자는 남자에게 무엇을 축하한다고 말했습니까?","audio":"지훈 씨, 정말 멋있네요. 결혼 축하해요. 신부 씨도 정말 아름다워요.","a":["생일","취업","이사","결혼"],"c":"결혼","ex":"Wanita tersebut mengucapkan selamat atas pernikahan Ji-hoon (결혼 축하해요).","romaji":"Yeojaneun namja-ege mueoseul chukhahandago malhaesseumnikka?","ch":34},{"id":"l_34_02","q":"돌잔치 선물로 무엇을 많이 합니까?","audio":"오늘 저녁에 돌잔치에 같이 가실 거죠? 예전에는 보통 금반지를 많이 선물했는데 요즘에는 금값이 너무 올라서 축의금을 내기도 해요.","a":["화분","세제","금반지","휴지"],"c":"금반지","ex":"Secara tradisional, cincin emas (금반지) adalah hadiah yang umum diberikan saat ulang tahun pertama bayi.","romaji":"Doljanchi seonmul-lo mueoseul mani hamnikka?","ch":34},{"id":"l_34_03","q":"남자는 장례식에 갈 때 무슨 색 옷을 입을 것입니까?","audio":"장례식장에 갈 때는 까만색 옷을 입고 가야 돼요. 그럼 집에 가서 까만색 옷을 입고 올게요. 잠시만 기다려 주세요.","a":["하얀색","빨간색","파란색","까만색"],"c":"까만색","ex":"Untuk pergi ke pemakaman, pria tersebut akan pulang untuk berganti pakaian warna hitam (까만색 옷).","romaji":"Namjaneun jangnyesige gal ttae museun saek oseul ibeul geosimnikka?","ch":34},{"id":"l_34_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"남: 오늘 저녁에 김 과장님 딸 돌잔치에 가요? 여: 네, 가야지요. 남자는 선물을 준비했어요? 남: 아니요, 아직 못 샀어요. 금반지를 살까요? 여: 요즘은 금값이 너무 비싸서 그냥 축의금을 내는 게 어때요? 남: 아, 그래요? 그럼 저도 축의금을 준비할게요.","a":["오늘 저녁에 돌잔치가 있습니다.","남자는 이미 금반지를 샀습니다.","여자는 남자에게 축의금을 추천했습니다.","요즘 금값이 많이 올랐습니다."],"c":"남자는 이미 금반지를 샀습니다.","ex":"Pria tersebut mengatakan belum membeli hadiah (아직 못 샀어요), jadi opsi B salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":34},{"id":"l_34_05","q":"집들이 선물에 대한 설명으로 알맞은 것은 무엇입니까?","audio":"한국 사람들은 이사를 한 후에 친구들을 초대하는 집들이를 합니다. 이때 손님들은 세제나 휴지를 선물로 사 갑니다. 휴지는 일이 잘 풀리라는 의미가 있고, 세제는 거품처럼 빨리 부자가 되라는 의미가 있습니다.","a":["휴지는 부자가 되라는 의미입니다.","세제는 건강하게 살라는 의미입니다.","세제는 빨리 부자가 되라는 의미가 있습니다.","집들이 때는 선물을 절대 가져가지 않습니다."],"c":"세제는 빨리 부자가 되라는 의미가 있습니다.","ex":"Deterjen (세제) melambangkan harapan agar penerima cepat menjadi kaya (빨리 부자가 되라는 의미).","romaji":"Jipdeuri seonmure daehan seolmyeong-euro almajeun geoseun mueosimnikka?","ch":34},{"id":"l_35_01","q":"수피카 씨는 누구를 제일 좋아합니까?","audio":"수피카 씨, 한국 연예인 중에 누구를 제일 좋아해요? 저는 빅뱅을 제일 좋아해요. 노래도 잘하고 아주 멋있잖아요.","a":["엑소","빅뱅","샤이니","방탄소년단"],"c":"빅뱅","ex":"Supika menyatakan dia paling suka Big Bang (빅뱅) karena mereka keren.","romaji":"Supika ssineun nugureul jeil joahamnikka?","ch":35},{"id":"l_35_02","q":"한국의 대표적인 수출품은 무엇입니까?","audio":"한국의 대표적인 수출품은 뭐예요? 예전에는 의류나 신발을 많이 수출했지만 요즘은 자동차나 전자제품이 유명해요.","a":["가구","신발","전자제품","식료품"],"c":"전자제품","ex":"Produk ekspor representatif saat ini adalah mobil dan produk elektronik (전자제품).","romaji":"Hangukui daepyojoegin suchulpumeun mueosimnikka?","ch":35},{"id":"l_35_03","q":"여자는 왜 한국 드라마를 좋아합니까?","audio":"흐엉 씨 고향에서도 한국 드라마가 인기가 있어요? 그럼요. 한국 드라마는 이야기 속의 배우들도 멋있고 내용이 재미있잖아요.","a":["배우가 없어서","한국어가 쉬워서","내용이 재미있어서","가격이 싸서"],"c":"내용이 재미있어서","ex":"Alasan yang disebutkan adalah karena ceritanya menarik (재미있잖아요).","romaji":"Yeojaneun wae Hanguk deuramareul joahamnikka?","ch":35},{"id":"l_35_04","q":"한류 열풍과 수출의 관계에 대한 설명으로 맞는 것은 무엇입니까?","audio":"한국 문화에 대한 관심이 높을수록 한국 상품의 수출도 늘어나고 있습니다. 특히 한류 스타들이 화장품 모델을 하면서 화장품 수출이 크게 증가했습니다. 중국과 아시아 지역에서 한국 화장품의 인기가 아주 높습니다.","a":["한류는 수출에 아무런 영향이 없습니다.","한국 화장품은 아시아에서 인기가 없습니다.","한류 스타 모델 덕분에 화장품 수출이 늘었습니다.","자동차 수출은 점점 줄어들고 있습니다."],"c":"한류 스타 모델 덕분에 화장품 수출이 늘었습니다.","ex":"Ekspor produk kosmetik meningkat drastis karena bintang Hallyu menjadi model iklan produk tersebut.","romaji":"Hallyu yeolpung-gwa suchulyi gwangye-e daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":35},{"id":"l_35_05","q":"두 사람은 지금 무엇을 할 것입니까?","audio":"여: 투안 씨, 이제 곧 제가 좋아하는 음악 프로그램이 시작되는데 같이 볼래요? 남: 좋아요. 저도 한국 노래를 참 좋아하거든요. 여: 그럼 텔레비전을 켤게요. 같이 봐요. 남: 네, 맛있는 간식도 가져올게요.","a":["영화를 보러 갑니다.","쇼핑을 하러 갑니다.","텔레비전을 봅니다.","한국어 공부를 합니다."],"c":"텔레비전을 봅니다.","ex":"Mereka sepakat untuk menonton program musik di televisi bersama (텔레비전을... 같이 봐요).","romaji":"Du sarameun jigeum mueoseul hal geosimnikka?","ch":35}];if(!window.Bank._listeningLoaded){["beginner","normal","pro"].forEach(function(lvl){if(window.Bank&&window.Bank[lvl]){if(!window.Bank[lvl].listening)window.Bank[lvl].listening=[];window.Bank[lvl].listening=window.Bank[lvl].listening.concat(items);}});window.Bank._listeningLoaded=true;}})();